(function(){
'use strict';
const APP_KEY='supermarket_pos_ar_v1';
const REST_FILES=['المطعم-لوحة-التحكم.html','المطعم-الطاولات.html','المطعم-المطبخ.html','المطعم-المنيو-الرقمي.html','المطعم-طلب-طاولة.html','المطعم-الوصفات-والتكاليف.html','المطعم-المخزون-الذكي.html','المطعم-الحجوزات.html','المطعم-التحليلات.html'];
const PAGES={
 dashboard:['المطعم-لوحة-التحكم.html','لوحة المطعم','الطاولات والطلبات والمحاسبة في مكان واحد'],
 tables:['المطعم-الطاولات.html','إدارة الطاولات','حالة كل طاولة: فارغة، مشغولة، محجوزة، تم التسليم، أو تحتاج تنظيف'],
 kitchen:['المطعم-المطبخ.html','شاشة المطبخ KDS','طلبات الزبائن تظهر وتتحرك بين مراحل التحضير دون تحديث الصفحة'],
 menu:['المطعم-المنيو-الرقمي.html','المنيو الرقمي و QR','أطباق، صور، إضافات، حذف مكونات، وروابط QR لكل طاولة'],
 public:['المطعم-طلب-طاولة.html','طلب الزبون','واجهة الطلب الذاتي من الهاتف'],
 recipes:['المطعم-الوصفات-والتكاليف.html','الوصفات والتكاليف','ربط كل طبق بمكوناته الخام وحساب التكلفة تلقائياً'],
 inventory:['المطعم-المخزون-الذكي.html','المخزون الذكي والهالك','خصم لحظي، حد الطلب، جرد، وهالك'],
 reservations:['المطعم-الحجوزات.html','حجوزات الطاولات','إدارة الحجوزات القادمة وربطها بالطاولات'],
 analytics:['المطعم-التحليلات.html','الأرباح والتحليلات','صافي الربح والأطباق الأعلى هامشاً']
};
const $=(id)=>document.getElementById(id);
const q=(s,p=document)=>p.querySelector(s);
const qa=(s,p=document)=>Array.from(p.querySelectorAll(s));
const esc=(v)=>String(v??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]));
const num=(v)=>Number(String(v??'').replace(/,/g,'')||0)||0;
const nowISO=()=>new Date().toISOString();
const today=()=>new Date().toISOString().slice(0,10);
const uid=(p='id')=>p+'-'+Date.now().toString(36)+'-'+Math.random().toString(36).slice(2,8);
function readDB(){try{return JSON.parse(localStorage.getItem(APP_KEY)||'{}')||{}}catch(e){return {}}}
function writeDB(db){localStorage.setItem(APP_KEY,JSON.stringify(db||{})); try{window.DB=db}catch(e){} scheduleSync(db);}
function coll(db,k){if(!Array.isArray(db[k]))db[k]=[]; return db[k];}
function active(rows){return (rows||[]).filter(x=>x && x._deleted!==true && !x.deletedAt)}
function settings(){const db=ensureDB(false); return db.settings||{};}
function currency(){return settings().currency||'₪'}
function money(v){return num(v).toFixed(2)+' '+currency()}
function userName(){try{return (JSON.parse(localStorage.getItem('currentUser')||'{}').name)||'مدير النظام'}catch(e){return 'مدير النظام'}}
function basePath(){return location.href.split('/').slice(0,-1).join('/')+'/'}
function pageUrl(file){return basePath()+encodeURIComponent(file).replace(/%2F/g,'/')}
function normalizeStatus(s){return String(s||'جديد')}
function isPaid(o){return num(o.due)<=0 || o.paymentStatus==='مدفوع'}
function productName(p){return p?.name||p?.productName||p?.title||p?.sku||'مادة خام'}
function productStock(p){return num(p?.stockUnits ?? p?.stock ?? p?.qty ?? p?.quantity)}
function setProductStock(p,val){if('stockUnits' in p)p.stockUnits=val; else p.stock=val; p._updatedAt=nowISO();}
function productCost(p){return num(p?.purchasePrice ?? p?.costPrice ?? p?.cost ?? p?.buyPrice ?? p?.unitCost ?? p?.price ?? p?.salePrice)}
function productUnit(p){return p?.unitShort||p?.unit||p?.baseUnit||p?.unitName||'وحدة'}
function ensureDB(save=true){let db=readDB(); db.settings=db.settings||{}; if(typeof db.settings.restaurantMode==='undefined')db.settings.restaurantMode=false; ['restaurantTables','restaurantMenuItems','restaurantRecipes','restaurantOrders','restaurantWastage','restaurantReservations','restaurantLoyalty','restaurantInventoryCounts','restaurantActivities','accountMovements','products','customers','sales','accounts','expenses'].forEach(k=>coll(db,k)); if(!db.accounts.length)db.accounts.push({id:'cash-main',name:'الصندوق الرئيسي',balance:0,active:'نشط'}); if(!db.restaurantTables.length){for(let i=1;i<=12;i++)db.restaurantTables.push({id:'rt-'+i,name:'طاولة '+i,code:'T'+String(i).padStart(2,'0'),capacity:i<=4?4:6,zone:i<=6?'الصالة الداخلية':'الخارجية',active:'نشط',createdAt:nowISO(),_updatedAt:nowISO()});}
 if(!db.restaurantMenuItems.length){db.restaurantMenuItems.push({id:'dish-1',name:'وجبة برجر خاصة',category:'وجبات',price:28,desc:'طبق تجريبي يمكن تعديله من المنيو الرقمي',active:'نشط',extras:['جبنة إضافية','صوص خاص'],removes:['بدون بصل','بدون مخلل'],prepTime:12,createdAt:nowISO(),_updatedAt:nowISO()},{id:'dish-2',name:'بيتزا مارجريتا',category:'بيتزا',price:34,desc:'مثال لطبق مع وصفة ومكونات خام',active:'نشط',extras:['جبنة إضافية','زيتون'],removes:['بدون صلصة'],prepTime:18,createdAt:nowISO(),_updatedAt:nowISO()});}
 if(save)writeDB(db); return db;}
function logAct(type,note,meta={}){const db=readDB(); coll(db,'restaurantActivities').unshift({id:uid('rlog'),date:new Date().toLocaleString('ar-EG',{hour12:false}),type,note,meta,createdBy:userName(),createdAt:nowISO()}); writeDB(db)}
function toast(msg){let el=$('rToast'); if(!el){el=document.createElement('div');el.id='rToast';el.className='r-toast';document.body.appendChild(el)} el.textContent=msg; el.style.display='block'; clearTimeout(el._t); el._t=setTimeout(()=>el.style.display='none',2400)}
let syncTimer=null, syncBusy=false; function scheduleSync(db){if(!navigator.onLine || !window.FirebaseBridge || syncBusy)return; clearTimeout(syncTimer); syncTimer=setTimeout(async()=>{try{syncBusy=true; showLoader('مزامنة المطعم...'); const merged=await window.FirebaseBridge.sync(db||readDB()); localStorage.setItem(APP_KEY,JSON.stringify(merged||readDB())); hideLoader();}catch(e){hideLoader()}finally{syncBusy=false}},850)}
async function pullFresh(){if(!navigator.onLine || !window.FirebaseBridge)return readDB(); try{showLoader('تحديث الطلبات...'); const db=await window.FirebaseBridge.sync(readDB()); localStorage.setItem(APP_KEY,JSON.stringify(db||readDB())); hideLoader(); return db||readDB();}catch(e){hideLoader(); return readDB();}}
function showLoader(t){let el=$('rLoader'); if(el){el.textContent=t||'تحميل...'; el.style.display='block'}} function hideLoader(){let el=$('rLoader'); if(el)el.style.display='none'}
function restaurantEnabled(){try{return !!readDB().settings?.restaurantMode}catch(e){return false}}
function statusBadge(s){s=normalizeStatus(s); let cls=s==='مدفوع'||s==='تم التسليم'||s==='فارغة'?'green':s==='ملغي'||s==='غير مدفوع'?'red':s==='تم التحضير'||s==='في الطريق للطاولة'?'blue':s==='قيد التحضير'||s==='محجوزة'||s==='تحتاج تنظيف'?'amber':'gray'; return `<span class="r-badge ${cls}">${esc(s)}</span>`}
function payBadge(o){return statusBadge(o.paymentStatus || (isPaid(o)?'مدفوع':'غير مدفوع'))}
function activeOrders(db){return active(db.restaurantOrders).filter(o=>!o.tableCleared && !['ملغي','مغلق'].includes(o.status));}
function tableOrders(db,tableId){return active(db.restaurantOrders).filter(o=>o.tableId===tableId && !o.tableCleared && !['ملغي','مغلق'].includes(o.status));}
function tableStatus(db,t){const open=tableOrders(db,t.id); if(open.some(o=>isPaid(o)))return 'تحتاج تنظيف'; if(open.some(o=>o.status==='تم التحضير'||o.status==='في الطريق للطاولة'))return 'جاهزة'; if(open.length)return 'مشغولة'; const r=active(db.restaurantReservations).find(x=>x.tableId===t.id && x.date===today() && !['ملغية','اكتملت'].includes(x.status)); return r?'محجوزة':'فارغة'}
function recipeFor(db,dishId){return active(db.restaurantRecipes).filter(r=>r.menuItemId===dishId)}
function costForDish(db,dish){return recipeFor(db,dish.id).reduce((s,r)=>{const p=active(db.products).find(x=>x.id===r.productId); return s+num(r.qty)*productCost(p)},0)}
function orderCost(db,o){return (o.items||[]).reduce((s,it)=>{const dish=active(db.restaurantMenuItems).find(d=>d.id===it.menuItemId); return s+(num(it.cost||costForDish(db,dish))*num(it.qty||1))},0)}
function deductRecipe(db,dishId,qty,orderId){recipeFor(db,dishId).forEach(r=>{const p=active(db.products).find(x=>x.id===r.productId); if(!p)return; const before=productStock(p); const after=before-num(r.qty)*num(qty||1); setProductStock(p,after); coll(db,'restaurantActivities').unshift({id:uid('rlog'),type:'خصم مخزون مطعم',note:`خصم ${num(r.qty)*num(qty||1)} ${productUnit(p)} من ${productName(p)}`,meta:{orderId,dishId,productId:p.id,before,after},createdBy:userName(),createdAt:nowISO(),date:new Date().toLocaleString('ar-EG',{hour12:false})});});}
function addAccountMovement(db,accountId,type,amount,source,note,sourceId){amount=num(amount); if(!amount)return; const acc=active(db.accounts).find(a=>a.id===accountId)||db.accounts[0]; if(!acc)return; const before=num(acc.balance), after=type==='in'?before+amount:before-amount; acc.balance=after; acc._updatedAt=nowISO(); coll(db,'accountMovements').unshift({id:uid('mov'),date:new Date().toLocaleString('ar-EG',{hour12:false}),accountId:acc.id,accountName:acc.name,type:type==='in'?'وارد':'صادر',amount,balanceBefore:before,balanceAfter:after,source,note,sourceId,createdBy:userName(),createdAt:nowISO(),_updatedAt:nowISO()});}
function createSaleFromOrder(db,o){if(coll(db,'sales').some(s=>s.sourceId==='restaurant_order:'+o.id))return; coll(db,'sales').unshift({id:uid('sale'),invoiceNo:o.orderNo||('R-'+Date.now()),date:new Date().toLocaleString('ar-EG',{hour12:false}),customerName:o.customerName||('طاولة '+(o.tableName||'')),customerPhone:o.customerPhone||'',items:(o.items||[]).map(i=>({productId:i.menuItemId,name:i.name,qty:i.qty,unitPrice:i.price,total:num(i.price)*num(i.qty),cost:i.cost||0})),subtotal:o.subtotal,total:o.total,paid:o.paid,due:o.due,paymentStatus:o.paymentStatus,source:'Restaurant OS',sourceId:'restaurant_order:'+o.id,createdBy:userName(),createdAt:nowISO(),_updatedAt:nowISO()});}
function recalcOrder(o){o.subtotal=(o.items||[]).reduce((s,i)=>s+num(i.qty)*num(i.price),0); o.discount=num(o.discount); o.service=num(o.service); o.tax=num(o.tax); o.total=Math.max(0,o.subtotal+o.service+o.tax-o.discount); o.paid=num(o.paid); o.due=Math.max(0,o.total-o.paid); o.paymentStatus=o.due<=0?'مدفوع':(o.paid>0?'مدفوع جزئياً':'غير مدفوع'); o._updatedAt=nowISO(); return o;}
function updateOrderStatus(id,status){const db=readDB(); const o=active(db.restaurantOrders).find(x=>x.id===id); if(!o)return; o.status=status; o._updatedAt=nowISO(); logActNoSave(db,'تغيير حالة طلب',`الطلب ${o.orderNo} أصبح ${status}`,{orderId:id}); writeDB(db); toast('تم تحديث حالة الطلب'); renderCurrent();}
function logActNoSave(db,type,note,meta={}){coll(db,'restaurantActivities').unshift({id:uid('rlog'),date:new Date().toLocaleString('ar-EG',{hour12:false}),type,note,meta,createdBy:userName(),createdAt:nowISO()});}
function payOrder(id,amount,accountId){const db=readDB(); const o=active(db.restaurantOrders).find(x=>x.id===id); if(!o)return; amount=num(amount||o.due||o.total); if(amount<=0)return toast('أدخل مبلغ صحيح'); o.paid=num(o.paid)+amount; recalcOrder(o); if(o.paymentStatus==='مدفوع' && !['تم التسليم','في الطريق للطاولة','تم التحضير'].includes(o.status))o.status='تم التسليم'; addAccountMovement(db,accountId||active(db.accounts)[0]?.id,'in',amount,'مطعم - تحصيل طلب',`تحصيل ${o.orderNo} / ${o.tableName||''}`,'restaurant_order:'+o.id); createSaleFromOrder(db,o); logActNoSave(db,'تحصيل طلب مطعم',`تم تحصيل ${money(amount)} من الطلب ${o.orderNo}`,{orderId:o.id}); writeDB(db); toast('تم تسجيل الدفع وتحديث الحسابات'); renderCurrent();}
function saveTable(form){const db=readDB(); const id=form.id.value||uid('rt'); let t=active(db.restaurantTables).find(x=>x.id===id); if(!t){t={id,createdAt:nowISO()}; db.restaurantTables.unshift(t)} t.name=form.name.value||'طاولة'; t.code=form.code.value||('T'+Date.now().toString().slice(-4)); t.zone=form.zone.value||''; t.capacity=num(form.capacity.value)||4; t.active=form.active.value||'نشط'; t._updatedAt=nowISO(); writeDB(db); toast('تم حفظ الطاولة'); closeModal(); renderCurrent();}
function saveMenuItem(form){const db=readDB(); const id=form.id.value||uid('dish'); let item=active(db.restaurantMenuItems).find(x=>x.id===id); if(!item){item={id,createdAt:nowISO()}; db.restaurantMenuItems.unshift(item)} item.name=form.name.value||'طبق'; item.category=form.category.value||'عام'; item.price=num(form.price.value); item.desc=form.desc.value||''; item.image=form.image.value||''; item.prepTime=num(form.prepTime.value)||10; item.active=form.active.value||'نشط'; item.extras=splitList(form.extras.value); item.removes=splitList(form.removes.value); item._updatedAt=nowISO(); writeDB(db); toast('تم حفظ الطبق'); closeModal(); renderCurrent();}
function splitList(v){return String(v||'').split(/[,،\n]/).map(x=>x.trim()).filter(Boolean)}
function saveRecipeRow(form){const db=readDB(); if(!form.menuItemId.value||!form.productId.value)return toast('اختر الطبق والمادة الخام'); const p=active(db.products).find(x=>x.id===form.productId.value); const id=form.id.value||uid('recipe'); let r=active(db.restaurantRecipes).find(x=>x.id===id); if(!r){r={id,createdAt:nowISO()}; db.restaurantRecipes.unshift(r)} r.menuItemId=form.menuItemId.value; r.productId=form.productId.value; r.productName=productName(p); r.qty=num(form.qty.value); r.unit=form.unit.value||productUnit(p); r.note=form.note.value||''; r._updatedAt=nowISO(); writeDB(db); toast('تم حفظ المكون وتحديث تكلفة الطبق'); closeModal(); renderCurrent();}
function addWastage(form){const db=readDB(); const p=active(db.products).find(x=>x.id===form.productId.value); if(!p)return toast('اختر المادة الخام'); const qty=num(form.qty.value); if(qty<=0)return toast('أدخل كمية صحيحة'); const before=productStock(p), after=before-qty; setProductStock(p,after); const amount=qty*productCost(p); coll(db,'restaurantWastage').unshift({id:uid('waste'),date:form.date.value||today(),productId:p.id,productName:productName(p),qty,unit:productUnit(p),cost:amount,reason:form.reason.value||'هالك مطعم',createdBy:userName(),createdAt:nowISO(),_updatedAt:nowISO()}); coll(db,'expenses').unshift({id:uid('exp'),date:new Date().toLocaleString('ar-EG',{hour12:false}),category:'هالك مطعم',amount,paid:0,due:amount,reason:form.reason.value||'هالك مطعم',source:'Restaurant OS',sourceId:'restaurant_wastage:'+p.id+':'+Date.now(),createdBy:userName(),createdAt:nowISO(),_updatedAt:nowISO()}); logActNoSave(db,'هالك مطعم',`تم تسجيل هالك ${qty} ${productUnit(p)} من ${productName(p)}`,{productId:p.id,before,after}); writeDB(db); toast('تم تسجيل الهالك وخصمه من المخزون والأرباح'); closeModal(); renderCurrent();}
function setReorder(productId,value){const db=readDB(); const p=active(db.products).find(x=>x.id===productId); if(!p)return; p.reorderPoint=num(value); p._updatedAt=nowISO(); writeDB(db); toast('تم حفظ حد الطلب'); renderCurrent();}
function saveInventoryCount(form){const db=readDB(); const p=active(db.products).find(x=>x.id===form.productId.value); if(!p)return toast('اختر المادة'); const actual=num(form.actual.value); const before=productStock(p); setProductStock(p,actual); coll(db,'restaurantInventoryCounts').unshift({id:uid('count'),date:form.date.value||today(),productId:p.id,productName:productName(p),systemQty:before,actualQty:actual,difference:actual-before,note:form.note.value||'',createdBy:userName(),createdAt:nowISO(),_updatedAt:nowISO()}); logActNoSave(db,'جرد مطعم',`تم تعديل مخزون ${productName(p)} من ${before} إلى ${actual}`,{productId:p.id}); writeDB(db); toast('تم حفظ الجرد وتعديل المخزون'); closeModal(); renderCurrent();}
function saveReservation(form){const db=readDB(); const id=form.id.value||uid('res'); let r=active(db.restaurantReservations).find(x=>x.id===id); if(!r){r={id,createdAt:nowISO()}; db.restaurantReservations.unshift(r)} const t=active(db.restaurantTables).find(x=>x.id===form.tableId.value); r.tableId=t?.id||''; r.tableName=t?.name||''; r.customerName=form.customerName.value||''; r.phone=form.phone.value||''; r.date=form.date.value||today(); r.time=form.time.value||''; r.guests=num(form.guests.value)||1; r.status=form.status.value||'محجوزة'; r.note=form.note.value||''; r._updatedAt=nowISO(); writeDB(db); toast('تم حفظ الحجز'); closeModal(); renderCurrent();}
function deleteRow(collection,id){const db=readDB(); const row=active(db[collection]).find(x=>x.id===id); if(!row)return; if(!confirm('تأكيد الحذف؟'))return; row._deleted=true; row.deletedAt=nowISO(); row._updatedAt=nowISO(); writeDB(db); toast('تم الحذف'); renderCurrent();}
function openModal(title,html,onSubmit){let back=$('rModalBack'); if(!back){back=document.createElement('div');back.id='rModalBack';back.className='r-modal-back';back.innerHTML='<div class="r-modal"><div class="r-modal-head"><h3 id="rModalTitle"></h3><button class="r-btn danger" type="button" data-close-modal>×</button></div><div id="rModalBody"></div></div>';document.body.appendChild(back);back.addEventListener('click',e=>{if(e.target===back||e.target.closest('[data-close-modal]'))closeModal()})} $('rModalTitle').textContent=title; $('rModalBody').innerHTML=html; back.style.display='flex'; const form=q('form',back); if(form){form.onsubmit=(e)=>{e.preventDefault(); onSubmit(form)}}}
function closeModal(){const b=$('rModalBack'); if(b)b.style.display='none'}
window.closeRestaurantModal=closeModal;
function nav(page){const links=[['dashboard','لوحة المطعم','🍽️'],['tables','الطاولات','▦'],['kitchen','المطبخ KDS','🔥'],['menu','المنيو و QR','▤'],['recipes','الوصفات والتكاليف','⚖️'],['inventory','المخزون والهالك','📦'],['reservations','الحجوزات','📅'],['analytics','الأرباح','📈']]; return `<aside class="r-sidebar" id="rSidebar"><a class="back" href="لوحة-المتابعة.html">↩ العودة للنظام الأساسي</a>${links.map(l=>`<a href="${PAGES[l[0]][0]}" class="${page===l[0]?'active':''}"><span>${l[2]}</span><b>${l[1]}</b></a>`).join('')}<a href="الإعدادات.html" class="back">⚙️ إعدادات وضع المطعم</a></aside>`}
function shell(page,content,actions=''){const p=PAGES[page]||PAGES.dashboard; return `<div class="r-shell"><header class="r-topbar"><button class="r-menu-btn" type="button" onclick="document.getElementById('rSidebar')?.classList.toggle('open')">☰</button><div class="r-brand"><span class="logo">🍽️</span><span>${esc(settings().storeName||'Restaurant OS')}</span></div><span class="r-live">متصل محليًا / مزامنة ذكية</span></header><div class="r-layout">${nav(page)}<main class="r-main"><section class="r-title"><div><h1>${p[1]}</h1><p>${p[2]}</p></div><div class="r-actions">${actions}</div></section><div id="rPageContent">${content}</div></main></div><div id="rLoader" class="r-loader"></div><div id="rToast" class="r-toast"></div></div>`}
function orderActions(o){return `<div class="r-actions"><button class="r-btn amber" onclick="RestaurantOS.status('${o.id}','قيد التحضير')">تحضير</button><button class="r-btn blue" onclick="RestaurantOS.status('${o.id}','تم التحضير')">جاهز</button><button class="r-btn blue" onclick="RestaurantOS.status('${o.id}','في الطريق للطاولة')">طلع للطاولة</button><button class="r-btn primary" onclick="RestaurantOS.status('${o.id}','تم التسليم')">تسلم</button><button class="r-btn dark" onclick="RestaurantOS.openPay('${o.id}')">محاسبة</button>${isPaid(o)?`<button class="r-btn danger" onclick="RestaurantOS.clearTable('${o.id}')">إفراغ الطاولة</button>`:''}</div>`}
function orderCard(o){return `<article class="r-order-card"><div class="r-order-head"><div><h3>${esc(o.orderNo||o.id)}</h3><div class="r-badge blue">${esc(o.tableName||'بدون طاولة')}</div> ${statusBadge(o.status)} ${payBadge(o)}</div><strong>${money(o.total)}</strong></div><div class="r-order-items">${(o.items||[]).map(i=>`<div class="r-order-item"><b>${num(i.qty)}× ${esc(i.name)}</b>${i.chefNote?`<div>ملاحظة الشيف: ${esc(i.chefNote)}</div>`:''}${(i.extras||[]).length?`<div>إضافات: ${esc((i.extras||[]).join('، '))}</div>`:''}${(i.removes||[]).length?`<div>حذف: ${esc((i.removes||[]).join('، '))}</div>`:''}</div>`).join('')}</div><div class="r-actions">${orderActions(o)}</div></article>`}
function dashboard(){const db=ensureDB(); const orders=active(db.restaurantOrders); const open=orders.filter(o=>!['مدفوع','ملغي','مغلق'].includes(o.status)); const todayOrders=orders.filter(o=>String(o.createdAt||'').slice(0,10)===today()); const rev=todayOrders.reduce((s,o)=>s+num(o.paid),0); const cost=todayOrders.reduce((s,o)=>s+orderCost(db,o),0); const waste=active(db.restaurantWastage).filter(w=>w.date===today()).reduce((s,w)=>s+num(w.cost),0); const due=open.reduce((s,o)=>s+num(o.due),0); const busy=active(db.restaurantTables).filter(t=>tableStatus(db,t)!=='فارغة').length; let content=`<section class="r-grid"><div class="r-kpi"><span>طلبات مفتوحة</span><strong>${open.length}</strong></div><div class="r-kpi"><span>طاولات مشغولة</span><strong>${busy}</strong></div><div class="r-kpi"><span>غير محاسب</span><strong>${money(due)}</strong></div><div class="r-kpi"><span>صافي اليوم</span><strong>${money(rev-cost-waste)}</strong></div></section><section class="r-card"><h2>الطلبات الحية</h2>${open.length?`<div class="r-grid-3">${open.slice(0,12).map(orderCard).join('')}</div>`:'<div class="r-empty">لا توجد طلبات مفتوحة الآن</div>'}</section><section class="r-card"><h2>خريطة الطاولات السريعة</h2><div class="r-table-grid">${active(db.restaurantTables).map(t=>{let st=tableStatus(db,t);return `<div class="r-table-card ${st==='فارغة'?'free':st==='جاهزة'?'ready':'busy'}"><h3>${esc(t.name)}</h3><p>${esc(t.zone||'الصالة')} · ${esc(t.capacity||4)} كراسي</p>${statusBadge(st)}<div class="r-actions" style="margin-top:10px"><a class="r-btn" href="المطعم-طلب-طاولة.html?table=${encodeURIComponent(t.id)}">رابط الطلب</a></div></div>`}).join('')}</div></section>`; return shell('dashboard',content,'<a class="r-btn primary" href="المطعم-المطبخ.html">افتح شاشة المطبخ</a><a class="r-btn" href="المطعم-المنيو-الرقمي.html">روابط QR</a>')}
function tables(){const db=ensureDB(); const content=`<section class="r-card"><h2>الطاولات</h2><div class="r-table-grid">${active(db.restaurantTables).map(t=>{let st=tableStatus(db,t), open=tableOrders(db,t.id); return `<div class="r-table-card ${st==='فارغة'?'free':st==='جاهزة'?'ready':'busy'}"><h3>${esc(t.name)}</h3><p>${esc(t.zone||'الصالة')} · ${esc(t.capacity||4)} كراسي</p>${statusBadge(st)}<p>طلبات مفتوحة: <b>${open.length}</b></p><div class="r-actions"><button class="r-btn" onclick="RestaurantOS.modalTable('${t.id}')">تعديل</button><a class="r-btn primary" href="المطعم-طلب-طاولة.html?table=${encodeURIComponent(t.id)}">منيو الطاولة</a><button class="r-btn danger" onclick="RestaurantOS.delete('restaurantTables','${t.id}')">حذف</button></div></div>`}).join('')}</div></section>`; return shell('tables',content,'<button class="r-btn primary" onclick="RestaurantOS.modalTable()">إضافة طاولة</button>')}
function kitchen(){const db=ensureDB(); const open=active(db.restaurantOrders).filter(o=>!isPaid(o) && !['ملغي','مغلق'].includes(o.status)); const buckets=['جديد','قيد التحضير','تم التحضير','في الطريق للطاولة','تم التسليم']; const content=`<section class="r-grid">${buckets.map(s=>`<div class="r-kpi"><span>${s}</span><strong>${open.filter(o=>o.status===s).length}</strong></div>`).join('')}</section><section class="r-card"><h2>شاشة الطلبات للمطبخ</h2>${open.length?`<div class="r-grid-3">${open.sort((a,b)=>String(a.createdAt).localeCompare(String(b.createdAt))).map(orderCard).join('')}</div>`:'<div class="r-empty">لا توجد طلبات للمطبخ</div>'}</section>`; return shell('kitchen',content,'<button class="r-btn" onclick="RestaurantOS.refresh()">تحديث</button><button class="r-btn primary" onclick="RestaurantOS.fullscreen()">ملء الشاشة</button>')}
function menuAdmin(){const db=ensureDB(); const tables=active(db.restaurantTables); const menu=active(db.restaurantMenuItems); const content=`<section class="r-grid-2"><div class="r-card"><h2>الأطباق</h2><div class="r-menu-grid">${menu.map(d=>`<article class="r-menu-item"><div class="r-menu-img">${d.image?`<img src="${esc(d.image)}" alt="">`:'🍽️'}</div><div class="r-menu-body"><h3>${esc(d.name)}</h3><p>${esc(d.desc||'')}</p><div class="r-menu-price">${money(d.price)}</div><p>تكلفة حالية: <b>${money(costForDish(db,d))}</b> · هامش: <b>${money(num(d.price)-costForDish(db,d))}</b></p><div class="r-actions"><button class="r-btn" onclick="RestaurantOS.modalMenu('${d.id}')">تعديل</button><button class="r-btn danger" onclick="RestaurantOS.delete('restaurantMenuItems','${d.id}')">حذف</button></div></div></article>`).join('')}</div></div><div class="r-card"><h2>روابط QR للطاولات</h2><div class="r-qr-grid">${tables.map(t=>{const link=pageUrl('المطعم-طلب-طاولة.html')+'?table='+encodeURIComponent(t.id); const qr='https://api.qrserver.com/v1/create-qr-code/?size=170x170&data='+encodeURIComponent(link); return `<div class="r-qr-card"><h3>${esc(t.name)}</h3><img src="${qr}" alt="QR"><input class="r-input" value="${esc(link)}" readonly onclick="this.select()"><button class="r-btn" onclick="navigator.clipboard&&navigator.clipboard.writeText('${esc(link)}');RestaurantOS.toast('تم نسخ الرابط')">نسخ الرابط</button></div>`}).join('')}</div></div></section>`; return shell('menu',content,'<button class="r-btn primary" onclick="RestaurantOS.modalMenu()">إضافة طبق</button><button class="r-btn" onclick="window.print()">طباعة QR</button>')}
function publicMenu(){ensureDB(); const tableId=new URLSearchParams(location.search).get('table')||''; const db=readDB(); const t=active(db.restaurantTables).find(x=>x.id===tableId)||active(db.restaurantTables)[0]||{id:'',name:'طاولة'}; const menu=active(db.restaurantMenuItems).filter(x=>x.active!=='غير نشط'); const orderId=localStorage.getItem('restaurant_last_order_'+t.id); const order=orderId&&active(db.restaurantOrders).find(o=>o.id===orderId); const content=`<div class="r-public"><section class="r-public-hero"><h1>${esc(settings().storeName||'منيو المطعم')}</h1><p>أنت تطلب الآن من: <b>${esc(t.name)}</b> — اختر أطباقك وسيصل الطلب مباشرة للمطبخ والكاشير.</p>${order?trackHTML(order):''}</section><div class="r-grid-2"><section class="r-card"><h2>المنيو الرقمي</h2><div class="r-menu-grid">${menu.map(d=>`<article class="r-menu-item"><div class="r-menu-img">${d.image?`<img src="${esc(d.image)}" alt="">`:'🍽️'}</div><div class="r-menu-body"><h3>${esc(d.name)}</h3><p>${esc(d.desc||'')}</p><div class="r-menu-price">${money(d.price)}</div><button class="r-btn primary" onclick="RestaurantOS.addCart('${d.id}')">إضافة للطلب</button></div></article>`).join('')}</div></section><aside class="r-card r-cart"><h2>طلبك</h2><div id="rCartBox"></div><div class="r-grid-2"><div class="r-field"><label>اسم الزبون</label><input id="rCustomerName" class="r-input" placeholder="اختياري"></div><div class="r-field"><label>رقم الهاتف للولاء</label><input id="rCustomerPhone" class="r-input" placeholder="اختياري"></div></div><button class="r-btn primary" style="width:100%;margin-top:12px" onclick="RestaurantOS.submitPublicOrder('${t.id}')">إرسال الطلب للمطبخ</button></aside></div></div><div id="rLoader" class="r-loader"></div><div id="rToast" class="r-toast"></div>`; setTimeout(renderCart,0); return content}
function trackHTML(o){const steps=['جديد','قيد التحضير','تم التحضير','في الطريق للطاولة']; return `<div><h3>حالة آخر طلب: ${esc(o.orderNo)}</h3><div class="r-progress">${steps.map(s=>`<div class="r-step ${steps.indexOf(s)<=Math.max(0,steps.indexOf(o.status))?'on':''}">${s}</div>`).join('')}</div></div>`}
let cart=[]; function renderCart(){const box=$('rCartBox'); if(!box)return; const db=readDB(); if(!cart.length){box.innerHTML='<div class="r-empty">السلة فارغة</div>';return} box.innerHTML=cart.map((i,idx)=>{const d=active(db.restaurantMenuItems).find(x=>x.id===i.id)||{}; return `<div class="r-cart-line"><div><b>${esc(d.name)}</b><div>${money(d.price)} × ${i.qty}</div><input class="r-input" placeholder="ملاحظات الشيف" value="${esc(i.note||'')}" onchange="RestaurantOS.cartNote(${idx},this.value)"><div>${(d.extras||[]).map(ex=>`<label style="display:block"><input type="checkbox" onchange="RestaurantOS.cartExtra(${idx},'${esc(ex)}',this.checked)"> ${esc(ex)}</label>`).join('')}${(d.removes||[]).map(re=>`<label style="display:block"><input type="checkbox" onchange="RestaurantOS.cartRemove(${idx},'${esc(re)}',this.checked)"> ${esc(re)}</label>`).join('')}</div></div><button class="r-btn" onclick="RestaurantOS.cartQty(${idx},1)">+</button><button class="r-btn danger" onclick="RestaurantOS.cartQty(${idx},-1)">-</button></div>`}).join('')+`<h3>الإجمالي: ${money(cart.reduce((s,i)=>{let d=active(db.restaurantMenuItems).find(x=>x.id===i.id)||{};return s+num(d.price)*i.qty},0))}</h3>`}
function submitPublicOrder(tableId){const db=readDB(); if(!cart.length)return toast('السلة فارغة'); const table=active(db.restaurantTables).find(x=>x.id===tableId)||{}; const order={id:uid('ro'),orderNo:'R-'+new Date().toISOString().replace(/[-:TZ.]/g,'').slice(2,14),tableId:table.id,tableName:table.name||'طاولة',customerName:$('rCustomerName')?.value||'',customerPhone:$('rCustomerPhone')?.value||'',status:'جديد',paymentStatus:'غير مدفوع',items:cart.map(c=>{const d=active(db.restaurantMenuItems).find(x=>x.id===c.id)||{}; const cost=costForDish(db,d); return {menuItemId:d.id,name:d.name,qty:c.qty,price:num(d.price),extras:c.extras||[],removes:c.removes||[],chefNote:c.note||'',cost};}),paid:0,createdAt:nowISO(),_updatedAt:nowISO(),createdBy:'زبون / منيو رقمي'}; recalcOrder(order); order.items.forEach(i=>deductRecipe(db,i.menuItemId,i.qty,order.id)); coll(db,'restaurantOrders').unshift(order); logActNoSave(db,'طلب جديد من الزبون',`طلب ${order.orderNo} من ${order.tableName}`,{orderId:order.id}); writeDB(db); localStorage.setItem('restaurant_last_order_'+table.id,order.id); cart=[]; toast('تم إرسال الطلب للمطبخ'); setTimeout(()=>location.reload(),800)}
function recipes(){const db=ensureDB(); const dishes=active(db.restaurantMenuItems), products=active(db.products); const rows=dishes.map(d=>{const cost=costForDish(db,d), margin=num(d.price)-cost, pct=num(d.price)?(margin/num(d.price))*100:0; return `<tr><td>${esc(d.name)}</td><td>${money(d.price)}</td><td>${money(cost)}</td><td>${money(margin)}</td><td>${pct.toFixed(1)}%</td><td>${recipeFor(db,d.id).map(r=>esc(r.productName)+' ('+r.qty+' '+esc(r.unit)+')').join('<br>')||'لا توجد وصفة'}</td><td><button class="r-btn" onclick="RestaurantOS.modalRecipe('', '${d.id}')">إضافة مكون</button></td></tr>`}).join(''); const content=`<section class="r-card"><h2>تكلفة الوصفات التلقائية</h2><p>أي تغيير على سعر شراء المادة الخام في الأصناف يغيّر تكلفة الطبق مباشرة هنا.</p><div class="r-table-wrap"><table class="r-table"><thead><tr><th>الطبق</th><th>سعر البيع</th><th>تكلفة المكونات</th><th>هامش الربح</th><th>النسبة</th><th>المكونات</th><th>إجراء</th></tr></thead><tbody>${rows}</tbody></table></div></section><section class="r-card"><h2>المواد الخام المتاحة</h2>${products.length?`<div class="r-table-wrap"><table class="r-table"><thead><tr><th>المادة</th><th>المخزون</th><th>تكلفة الوحدة</th><th>حد الطلب</th></tr></thead><tbody>${products.slice(0,80).map(p=>`<tr><td>${esc(productName(p))}</td><td>${productStock(p)} ${esc(productUnit(p))}</td><td>${money(productCost(p))}</td><td>${esc(p.reorderPoint||0)}</td></tr>`).join('')}</tbody></table></div>`:'<div class="r-empty">أضف مواد خام من صفحة الأصناف حتى تظهر هنا.</div>'}</section>`; return shell('recipes',content,'<button class="r-btn primary" onclick="RestaurantOS.modalRecipe()">ربط مكون بوصفة</button>')}
function inventory(){const db=ensureDB(); const products=active(db.products); const alerts=products.filter(p=>num(p.reorderPoint)>0 && productStock(p)<=num(p.reorderPoint)); const content=`<section class="r-grid"><div class="r-kpi"><span>مواد تحت حد الطلب</span><strong>${alerts.length}</strong></div><div class="r-kpi"><span>هالك اليوم</span><strong>${money(active(db.restaurantWastage).filter(w=>w.date===today()).reduce((s,w)=>s+num(w.cost),0))}</strong></div><div class="r-kpi"><span>عمليات جرد</span><strong>${active(db.restaurantInventoryCounts).length}</strong></div><div class="r-kpi"><span>مواد خام</span><strong>${products.length}</strong></div></section><section class="r-card"><h2>تنبيهات حد الطلب</h2>${alerts.length?`<div class="r-table-wrap"><table class="r-table"><thead><tr><th>المادة</th><th>المخزون الحالي</th><th>حد الطلب</th><th>تعديل الحد</th></tr></thead><tbody>${alerts.map(p=>productInventoryRow(p)).join('')}</tbody></table></div>`:'<div class="r-empty">لا توجد مواد تحت حد الطلب الآن</div>'}</section><section class="r-card"><h2>كل المواد الخام والجرد</h2><div class="r-table-wrap"><table class="r-table"><thead><tr><th>المادة</th><th>المخزون</th><th>تكلفة الوحدة</th><th>حد الطلب</th><th>إجراء</th></tr></thead><tbody>${products.map(p=>productInventoryRow(p)).join('')}</tbody></table></div></section><section class="r-card"><h2>سجل الهالك</h2><div class="r-table-wrap"><table class="r-table"><thead><tr><th>التاريخ</th><th>المادة</th><th>الكمية</th><th>التكلفة</th><th>السبب</th></tr></thead><tbody>${active(db.restaurantWastage).slice(0,80).map(w=>`<tr><td>${esc(w.date)}</td><td>${esc(w.productName)}</td><td>${w.qty} ${esc(w.unit)}</td><td>${money(w.cost)}</td><td>${esc(w.reason)}</td></tr>`).join('')}</tbody></table></div></section>`; return shell('inventory',content,'<button class="r-btn primary" onclick="RestaurantOS.modalWaste()">تسجيل هالك</button><button class="r-btn" onclick="RestaurantOS.modalCount()">جرد فعلي</button>')}
function productInventoryRow(p){return `<tr><td>${esc(productName(p))}</td><td>${productStock(p)} ${esc(productUnit(p))}</td><td>${money(productCost(p))}</td><td><input class="r-input" style="width:110px" value="${esc(p.reorderPoint||0)}" onchange="RestaurantOS.reorder('${p.id}',this.value)"></td><td><button class="r-btn" onclick="RestaurantOS.modalCount('${p.id}')">جرد</button></td></tr>`}
function reservations(){const db=ensureDB(); const rows=active(db.restaurantReservations).map(r=>`<tr><td>${esc(r.date)} ${esc(r.time||'')}</td><td>${esc(r.tableName)}</td><td>${esc(r.customerName)}</td><td>${esc(r.phone)}</td><td>${esc(r.guests)}</td><td>${statusBadge(r.status)}</td><td>${esc(r.note)}</td><td><button class="r-btn" onclick="RestaurantOS.modalReservation('${r.id}')">تعديل</button><button class="r-btn danger" onclick="RestaurantOS.delete('restaurantReservations','${r.id}')">حذف</button></td></tr>`).join(''); const content=`<section class="r-card"><h2>الحجوزات</h2><div class="r-table-wrap"><table class="r-table"><thead><tr><th>الموعد</th><th>الطاولة</th><th>الزبون</th><th>الهاتف</th><th>عدد الأشخاص</th><th>الحالة</th><th>ملاحظة</th><th>إجراء</th></tr></thead><tbody>${rows}</tbody></table></div></section>`; return shell('reservations',content,'<button class="r-btn primary" onclick="RestaurantOS.modalReservation()">حجز جديد</button>')}
function analytics(){const db=ensureDB(); const orders=active(db.restaurantOrders).filter(o=>o.status!=='ملغي'); const from=$('fromDate')?.value||today().slice(0,8)+'01', to=$('toDate')?.value||today(); const filtered=orders.filter(o=>{const d=String(o.createdAt||'').slice(0,10); return d>=from && d<=to}); const sales=filtered.reduce((s,o)=>s+num(o.total),0), paid=filtered.reduce((s,o)=>s+num(o.paid),0), costs=filtered.reduce((s,o)=>s+orderCost(db,o),0); const waste=active(db.restaurantWastage).filter(w=>w.date>=from && w.date<=to).reduce((s,w)=>s+num(w.cost),0); const opEx=active(db.expenses).filter(e=>String(e.date||e.createdAt||'').slice(0,10)>=from&&String(e.date||e.createdAt||'').slice(0,10)<=to&&e.category!=='هالك مطعم').reduce((s,e)=>s+num(e.amount),0); const dishStats={}; filtered.forEach(o=>(o.items||[]).forEach(i=>{const d=active(db.restaurantMenuItems).find(x=>x.id===i.menuItemId)||{}; const c=i.cost||costForDish(db,d); dishStats[i.menuItemId]=dishStats[i.menuItemId]||{name:i.name,qty:0,sales:0,cost:0}; dishStats[i.menuItemId].qty+=num(i.qty); dishStats[i.menuItemId].sales+=num(i.price)*num(i.qty); dishStats[i.menuItemId].cost+=num(c)*num(i.qty)})); const stats=Object.values(dishStats).map(x=>({...x,profit:x.sales-x.cost,margin:x.sales?((x.sales-x.cost)/x.sales)*100:0})).sort((a,b)=>b.profit-a.profit); const max=Math.max(1,...stats.map(s=>s.profit)); const content=`<section class="r-card"><div class="r-grid-2"><div class="r-field"><label>من تاريخ</label><input class="r-input" id="fromDate" type="date" value="${esc(from)}" onchange="RestaurantOS.renderAnalytics()"></div><div class="r-field"><label>إلى تاريخ</label><input class="r-input" id="toDate" type="date" value="${esc(to)}" onchange="RestaurantOS.renderAnalytics()"></div></div></section><section class="r-grid"><div class="r-kpi"><span>إجمالي المبيعات</span><strong>${money(sales)}</strong></div><div class="r-kpi"><span>المدفوع فعليًا</span><strong>${money(paid)}</strong></div><div class="r-kpi"><span>تكلفة المكونات</span><strong>${money(costs)}</strong></div><div class="r-kpi"><span>صافي الربح</span><strong>${money(sales-costs-waste-opEx)}</strong></div></section><section class="r-card"><h2>معادلة الربح</h2><p><b>صافي الربح = سعر البيع - تكلفة المكونات - الهالك - المصاريف التشغيلية</b></p><div class="r-grid"><div class="r-kpi"><span>الهالك</span><strong>${money(waste)}</strong></div><div class="r-kpi"><span>المصاريف التشغيلية</span><strong>${money(opEx)}</strong></div><div class="r-kpi"><span>غير محصل</span><strong>${money(filtered.reduce((s,o)=>s+num(o.due),0))}</strong></div><div class="r-kpi"><span>عدد الطلبات</span><strong>${filtered.length}</strong></div></div></section><section class="r-card"><h2>الأطباق الأكثر ربحية Menu Engineering</h2>${stats.length?`<div class="r-bars">${stats.slice(0,20).map(s=>`<div class="r-bar"><b>${esc(s.name)}</b><div class="r-bar-track"><div class="r-bar-fill" style="width:${Math.max(4,(s.profit/max)*100)}%"></div></div><span>${money(s.profit)} · ${s.margin.toFixed(1)}%</span></div>`).join('')}</div>`:'<div class="r-empty">لا توجد مبيعات في الفترة المحددة</div>'}</section>`; return shell('analytics',content,'<button class="r-btn" onclick="window.print()">طباعة التقرير</button>')}
function renderAnalyticsOnly(){const root=$('rPageContent'); if(root){const html=analytics(); document.body.innerHTML=html; setTimeout(()=>{q('#fromDate')&&(q('#fromDate').value=localStorage.rFrom||q('#fromDate').value)},0)}}
function modalTable(id=''){const db=readDB(); const t=active(db.restaurantTables).find(x=>x.id===id)||{}; openModal(id?'تعديل طاولة':'إضافة طاولة',`<form><input type="hidden" name="id" value="${esc(t.id||'')}"><div class="r-grid-2"><div class="r-field"><label>اسم الطاولة</label><input class="r-input" name="name" value="${esc(t.name||'')}"></div><div class="r-field"><label>الكود</label><input class="r-input" name="code" value="${esc(t.code||'')}"></div><div class="r-field"><label>المنطقة</label><input class="r-input" name="zone" value="${esc(t.zone||'')}"></div><div class="r-field"><label>عدد الكراسي</label><input class="r-input" type="number" name="capacity" value="${esc(t.capacity||4)}"></div><div class="r-field"><label>الحالة</label><select class="r-select" name="active"><option ${t.active!=='غير نشط'?'selected':''}>نشط</option><option ${t.active==='غير نشط'?'selected':''}>غير نشط</option></select></div></div><button class="r-btn primary" style="margin-top:12px">حفظ</button></form>`,saveTable)}
function modalMenu(id=''){const db=readDB(); const d=active(db.restaurantMenuItems).find(x=>x.id===id)||{}; openModal(id?'تعديل طبق':'إضافة طبق',`<form><input type="hidden" name="id" value="${esc(d.id||'')}"><div class="r-grid-2"><div class="r-field"><label>اسم الطبق</label><input class="r-input" name="name" value="${esc(d.name||'')}"></div><div class="r-field"><label>التصنيف</label><input class="r-input" name="category" value="${esc(d.category||'')}"></div><div class="r-field"><label>سعر البيع</label><input class="r-input" type="number" step="0.01" name="price" value="${esc(d.price||0)}"></div><div class="r-field"><label>وقت التحضير بالدقائق</label><input class="r-input" type="number" name="prepTime" value="${esc(d.prepTime||10)}"></div><div class="r-field"><label>رابط صورة الطبق</label><input class="r-input" name="image" value="${esc(d.image||'')}"></div><div class="r-field"><label>الحالة</label><select class="r-select" name="active"><option ${d.active!=='غير نشط'?'selected':''}>نشط</option><option ${d.active==='غير نشط'?'selected':''}>غير نشط</option></select></div><div class="r-field"><label>الإضافات Extra</label><textarea class="r-textarea" name="extras">${esc((d.extras||[]).join('\n'))}</textarea></div><div class="r-field"><label>الحذف Remove</label><textarea class="r-textarea" name="removes">${esc((d.removes||[]).join('\n'))}</textarea></div><div class="r-field" style="grid-column:1/-1"><label>وصف الطبق</label><textarea class="r-textarea" name="desc">${esc(d.desc||'')}</textarea></div></div><button class="r-btn primary" style="margin-top:12px">حفظ</button></form>`,saveMenuItem)}
function productOptions(selected=''){const db=readDB(); return active(db.products).map(p=>`<option value="${esc(p.id)}" ${p.id===selected?'selected':''}>${esc(productName(p))} — ${productStock(p)} ${esc(productUnit(p))}</option>`).join('')}
function dishOptions(selected=''){const db=readDB(); return active(db.restaurantMenuItems).map(d=>`<option value="${esc(d.id)}" ${d.id===selected?'selected':''}>${esc(d.name)}</option>`).join('')}
function modalRecipe(id='',dishId=''){const db=readDB(); const r=active(db.restaurantRecipes).find(x=>x.id===id)||{menuItemId:dishId}; openModal('ربط مكون خام بالطبق',`<form><input type="hidden" name="id" value="${esc(r.id||'')}"><div class="r-grid-2"><div class="r-field"><label>الطبق</label><select class="r-select" name="menuItemId"><option value="">اختر الطبق</option>${dishOptions(r.menuItemId)}</select></div><div class="r-field"><label>المادة الخام</label><select class="r-select" name="productId"><option value="">اختر المادة</option>${productOptions(r.productId)}</select></div><div class="r-field"><label>الكمية المستخدمة لكل طبق</label><input class="r-input" name="qty" type="number" step="0.001" value="${esc(r.qty||0)}"></div><div class="r-field"><label>الوحدة</label><input class="r-input" name="unit" value="${esc(r.unit||'وحدة')}"></div><div class="r-field" style="grid-column:1/-1"><label>ملاحظة</label><input class="r-input" name="note" value="${esc(r.note||'')}"></div></div><button class="r-btn primary" style="margin-top:12px">حفظ</button></form>`,saveRecipeRow)}
function modalWaste(){openModal('تسجيل هالك مطعم',`<form><div class="r-grid-2"><div class="r-field"><label>التاريخ</label><input class="r-input" type="date" name="date" value="${today()}"></div><div class="r-field"><label>المادة الخام</label><select class="r-select" name="productId"><option value="">اختر المادة</option>${productOptions()}</select></div><div class="r-field"><label>الكمية التالفة</label><input class="r-input" type="number" step="0.001" name="qty"></div><div class="r-field"><label>السبب</label><input class="r-input" name="reason" placeholder="تلف، انتهاء صلاحية، حرق..."></div></div><button class="r-btn primary" style="margin-top:12px">تسجيل الهالك</button></form>`,addWastage)}
function modalCount(productId=''){openModal('جرد فعلي لمادة خام',`<form><div class="r-grid-2"><div class="r-field"><label>التاريخ</label><input class="r-input" type="date" name="date" value="${today()}"></div><div class="r-field"><label>المادة</label><select class="r-select" name="productId"><option value="">اختر المادة</option>${productOptions(productId)}</select></div><div class="r-field"><label>الكمية الفعلية</label><input class="r-input" type="number" step="0.001" name="actual"></div><div class="r-field"><label>ملاحظة</label><input class="r-input" name="note"></div></div><button class="r-btn primary" style="margin-top:12px">حفظ الجرد</button></form>`,saveInventoryCount)}
function modalReservation(id=''){const db=readDB(); const r=active(db.restaurantReservations).find(x=>x.id===id)||{}; openModal(id?'تعديل حجز':'حجز طاولة جديد',`<form><input type="hidden" name="id" value="${esc(r.id||'')}"><div class="r-grid-2"><div class="r-field"><label>الطاولة</label><select class="r-select" name="tableId"><option value="">اختر طاولة</option>${active(db.restaurantTables).map(t=>`<option value="${esc(t.id)}" ${r.tableId===t.id?'selected':''}>${esc(t.name)}</option>`).join('')}</select></div><div class="r-field"><label>اسم الزبون</label><input class="r-input" name="customerName" value="${esc(r.customerName||'')}"></div><div class="r-field"><label>الهاتف</label><input class="r-input" name="phone" value="${esc(r.phone||'')}"></div><div class="r-field"><label>عدد الأشخاص</label><input class="r-input" type="number" name="guests" value="${esc(r.guests||1)}"></div><div class="r-field"><label>التاريخ</label><input class="r-input" type="date" name="date" value="${esc(r.date||today())}"></div><div class="r-field"><label>الوقت</label><input class="r-input" type="time" name="time" value="${esc(r.time||'')}"></div><div class="r-field"><label>الحالة</label><select class="r-select" name="status"><option ${r.status==='محجوزة'?'selected':''}>محجوزة</option><option ${r.status==='اكتملت'?'selected':''}>اكتملت</option><option ${r.status==='ملغية'?'selected':''}>ملغية</option></select></div><div class="r-field"><label>ملاحظة</label><input class="r-input" name="note" value="${esc(r.note||'')}"></div></div><button class="r-btn primary" style="margin-top:12px">حفظ الحجز</button></form>`,saveReservation)}
function openPay(id){const db=readDB(); const o=active(db.restaurantOrders).find(x=>x.id===id); if(!o)return; const accounts=active(db.accounts); openModal('محاسبة الطلب '+(o.orderNo||''),`<form><div class="r-grid-2"><div class="r-kpi"><span>الإجمالي</span><strong>${money(o.total)}</strong></div><div class="r-kpi"><span>المتبقي</span><strong>${money(o.due)}</strong></div><div class="r-field"><label>المبلغ المدفوع الآن</label><input class="r-input" type="number" step="0.01" name="amount" value="${esc(o.due||o.total)}"></div><div class="r-field"><label>حساب دخول المال</label><select class="r-select" name="accountId">${accounts.map(a=>`<option value="${esc(a.id)}">${esc(a.name)} — ${money(a.balance)}</option>`).join('')}</select></div></div><button class="r-btn primary" style="margin-top:12px">تسجيل الدفع</button></form>`,(form)=>payOrder(id,form.amount.value,form.accountId.value))}
function installSettingsCard(){if(!/الإعدادات\.html$/.test(decodeURIComponent(location.pathname)))return; const tryInstall=()=>{const main=$('mainCard')||q('.card'); if(!main||$('restaurantSettingsCard'))return; const on=restaurantEnabled(); main.insertAdjacentHTML('afterbegin',`<div id="restaurantSettingsCard" class="restaurant-settings-card"><div class="restaurant-settings-head"><div class="restaurant-settings-title"><div class="restaurant-settings-icon">🍽️</div><div><h3>وضع المطعم Restaurant OS</h3><p>عند التفعيل تظهر أقسام الطاولات، المطبخ، المنيو الرقمي، الوصفات، المخزون الذكي، الحجوزات والتحليلات، وتختفي واجهات البيع المباشر العادية من القائمة حتى لا تختلط مع المطعم.</p></div></div><label class="restaurant-toggle"><input id="restaurantModeToggle" type="checkbox" ${on?'checked':''}><span></span></label></div><div class="restaurant-settings-actions"><a class="primary" href="المطعم-لوحة-التحكم.html">فتح لوحة المطعم</a><a href="المطعم-الطاولات.html">الطاولات</a><a href="المطعم-المطبخ.html">المطبخ KDS</a><a href="المطعم-المنيو-الرقمي.html">المنيو و QR</a><a href="المطعم-التحليلات.html">الأرباح</a></div><p><span class="restaurant-mode-badge">${on?'وضع المطعم مفعل':'وضع المطعم متوقف'}</span></p></div>`); const toggle=$('restaurantModeToggle'); toggle.onchange=()=>{const db=ensureDB(false); db.settings=db.settings||{}; db.settings.restaurantMode=toggle.checked; db.settings._updatedAt=nowISO(); writeDB(db); toast(toggle.checked?'تم تفعيل وضع المطعم':'تم إيقاف وضع المطعم'); setTimeout(()=>location.reload(),350)};}; setTimeout(tryInstall,80); setTimeout(tryInstall,400); setTimeout(tryInstall,1200)}
function installRestaurantMenu(){const tryInstall=()=>{const menu=q('.drawer .menu'); if(!menu||$('restaurantDrawerGroup'))return; const enabled=restaurantEnabled(); const html=`<div class="menu-group restaurant-drawer-group ${enabled?'open':''}" id="restaurantDrawerGroup"><button class="menu-head" onclick="window.toggleMenu&&window.toggleMenu(this)"><span class="mi"><svg viewBox="0 0 24 24"><path d="M4 3v8a4 4 0 0 0 8 0V3"/><path d="M8 3v18"/><path d="M19 3v18"/><path d="M15 3h4v8h-4z"/></svg></span><b>وضع المطعم</b><span class="arrow">‹</span></button><div class="submenu"><a class="sub" href="المطعم-لوحة-التحكم.html">لوحة المطعم</a><a class="sub" href="المطعم-الطاولات.html">الطاولات</a><a class="sub" href="المطعم-المطبخ.html">المطبخ KDS</a><a class="sub" href="المطعم-المنيو-الرقمي.html">المنيو الرقمي و QR</a><a class="sub" href="المطعم-الوصفات-والتكاليف.html">الوصفات والتكاليف</a><a class="sub" href="المطعم-المخزون-الذكي.html">المخزون والهالك</a><a class="sub" href="المطعم-الحجوزات.html">الحجوزات</a><a class="sub" href="المطعم-التحليلات.html">الأرباح والتحليلات</a></div></div>`; menu.insertAdjacentHTML('afterbegin',html); if(enabled){qa('.menu-group').forEach(g=>{const txt=q('.menu-head b',g)?.textContent||''; if(/المبيعات/.test(txt) && !g.id)g.classList.add('restaurant-menu-hidden');}); const bn=q('.bottom-nav'); if(bn){bn.classList.add('restaurant-bottom-nav'); bn.innerHTML='<a href="المطعم-لوحة-التحكم.html"><b>🍽️</b><span>المطعم</span></a><a href="المطعم-الطاولات.html"><b>▦</b><span>الطاولات</span></a><a href="المطعم-المطبخ.html"><b>🔥</b><span>المطبخ</span></a><a href="المطعم-المنيو-الرقمي.html"><b>QR</b><span>المنيو</span></a><a href="الإعدادات.html"><b>⚙</b><span>الإعدادات</span></a>';}}}; setTimeout(tryInstall,120); setTimeout(tryInstall,600); setTimeout(tryInstall,1400)}
function renderCurrent(){const page=document.body?.dataset?.restaurantPage; if(!page)return; if(page==='public'){document.body.innerHTML=publicMenu(); return} const renderers={dashboard,tables,kitchen,menu:menuAdmin,recipes,inventory,reservations,analytics}; document.body.innerHTML=(renderers[page]||dashboard)(); if(page==='analytics'){setTimeout(()=>{},0)}}
function initRestaurantPage(){const page=document.body?.dataset?.restaurantPage; if(!page)return; document.body.classList.add('restaurant-page'); ensureDB(); renderCurrent(); if(page==='kitchen'||page==='dashboard'||page==='public'||page==='tables'){setInterval(async()=>{const before=JSON.stringify(readDB().restaurantOrders||[]); await pullFresh(); const after=JSON.stringify(readDB().restaurantOrders||[]); if(before!==after)renderCurrent();}, page==='public'?3500:2200)} if('serviceWorker' in navigator){try{navigator.serviceWorker.register('sw.js')}catch(e){}}}
window.RestaurantOS={toast,status:updateOrderStatus,openPay,modalTable,modalMenu,modalRecipe,modalWaste,modalCount,modalReservation,delete:deleteRow,reorder:setReorder,refresh:()=>pullFresh().then(renderCurrent),fullscreen:()=>document.documentElement.requestFullscreen&&document.documentElement.requestFullscreen(),addCart(id){const found=cart.find(x=>x.id===id); if(found)found.qty++; else cart.push({id,qty:1,extras:[],removes:[],note:''}); renderCart();},cartQty(i,d){if(!cart[i])return; cart[i].qty+=d; if(cart[i].qty<=0)cart.splice(i,1); renderCart();},cartNote(i,v){if(cart[i])cart[i].note=v},cartExtra(i,v,on){if(!cart[i])return; cart[i].extras=cart[i].extras||[]; cart[i].extras=on?[...new Set([...cart[i].extras,v])]:cart[i].extras.filter(x=>x!==v)},cartRemove(i,v,on){if(!cart[i])return; cart[i].removes=cart[i].removes||[]; cart[i].removes=on?[...new Set([...cart[i].removes,v])]:cart[i].removes.filter(x=>x!==v)},submitPublicOrder,renderAnalytics:()=>renderCurrent(),clearTable(id){const db=readDB(); const o=active(db.restaurantOrders).find(x=>x.id===id); if(!o)return; if(!isPaid(o))return toast('لا يمكن إفراغ الطاولة قبل المحاسبة'); o.tableCleared=true; o.status='مغلق'; o._updatedAt=nowISO(); logActNoSave(db,'إفراغ طاولة',`تم إفراغ ${o.tableName||'طاولة'} بعد محاسبة ${o.orderNo}`,{orderId:id}); writeDB(db); toast('تم إفراغ الطاولة وأصبحت جاهزة'); renderCurrent();}};
function init(){ensureDB(false); installSettingsCard(); installRestaurantMenu(); initRestaurantPage();}
if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',init); else init();
})();
